  logic        SPIOut;
  logic [3:0]  SPICS;

  logic        HREADY;
  logic        HSELEXT;
  logic        HSELEXTSDC;
  logic        ExternalStall;

  // instantiate device to be tested
  assign GPIOIN = 0;
  assign UARTSin = 1;

